class Solution:
    def minimumChanges(self, s: str, k: int) -> int:
        n = len(s)

        # Precompute cost to make each substring s[i:j] a semi-palindrome
        cost = [[0] * (n + 1) for _ in range(n + 1)]
        for i in range(n):
            for j in range(i + 1, n + 1):
                substring = s[i:j]
                # Compute cost to make substring a semi-palindrome
                min_cost = float('inf')
                len_sub = len(substring)
                for d in range(1, len_sub):
                    if len_sub % d == 0:
                        # Check if it's a semi-palindrome
                        groups = []
                        for idx in range(len_sub):
                            group = idx % d
                            groups.append(group)
                        # Count changes needed to make each group a palindrome
                        changes = 0
                        for g in range(d):
                            group_chars = [substring[i] for i in range(len_sub) if groups[i] == g]
                            # Count changes to make this group a palindrome
                            left, right = 0, len(group_chars) - 1
                            while left < right:
                                if group_chars[left] != group_chars[right]:
                                    changes += 1
                                left += 1
                                right -= 1
                        min_cost = min(min_cost, changes)
                cost[i][j] = min_cost

        # Dynamic Programming to partition the string into k parts
        dp = [[float('inf')] * (n + 1) for _ in range(k + 1)]
        dp[0][0] = 0

        for parts in range(1, k + 1):
            for i in range(n + 1):
                for j in range(i + 1, n + 1):
                    if dp[parts - 1][i] + cost[i][j] < dp[parts][j]:
                        dp[parts][j] = dp[parts - 1][i] + cost[i][j]

        return int(dp[k][n])
